export async function getResolveInstructionAsync<
  TAccountVrfProgramIdentity extends string,
  TAccountGame extends string,
  TAccountPlayer extends string,
  TAccountSystemProgram extends string,
  TProgramAddress extends Address = typeof HORMUZ_RUN_PROGRAM_ADDRESS,
>(
  input: ResolveAsyncInput<
    TAccountVrfProgramIdentity,
    TAccountGame,
    TAccountPlayer,
    TAccountSystemProgram
  >,
  config?: { programAddress?: TProgramAddress },
): Promise<
  ResolveInstruction<
    TProgramAddress,
    TAccountVrfProgramIdentity,
    TAccountGame,
    TAccountPlayer,
    TAccountSystemProgram
  >
> {
  // Program address.
  const programAddress = config?.programAddress ?? HORMUZ_RUN_PROGRAM_ADDRESS;

  // Original accounts.
  const originalAccounts = {
    vrfProgramIdentity: {
      value: input.vrfProgramIdentity ?? null,
      isWritable: false,
    },
    game: { value: input.game ?? null, isWritable: true },
    player: { value: input.player ?? null, isWritable: true },
    systemProgram: { value: input.systemProgram ?? null, isWritable: false },
  };
  const accounts = originalAccounts as Record<
    keyof typeof originalAccounts,
    ResolvedInstructionAccount
  >;

  // Original args.
  const args = { ...input };

  // Resolve default values.
  if (!accounts.game.value) {
    accounts.game.value = await findGamePda();
  }
  if (!accounts.systemProgram.value) {
    accounts.systemProgram.value =
      "11111111111111111111111111111111" as Address<"11111111111111111111111111111111">;
  }

  const getAccountMeta = getAccountMetaFactory(programAddress, "programId");
  return Object.freeze({
    accounts: [
      getAccountMeta("vrfProgramIdentity", accounts.vrfProgramIdentity),
      getAccountMeta("game", accounts.game),
      getAccountMeta("player", accounts.player),
      getAccountMeta("systemProgram", accounts.systemProgram),
    ],
    data: getResolveInstructionDataEncoder().encode(
      args as ResolveInstructionDataArgs,
    ),
    programAddress,
  } as ResolveInstruction<
    TProgramAddress,
    TAccountVrfProgramIdentity,
    TAccountGame,
    TAccountPlayer,
    TAccountSystemProgram
  >);
}

